import pytest

from conftest import build_cache, run_script, write_blast_radius_map, read_json, repo_pollution
import graphify_lib

AC_UID = "143a78ee122ff4cb"
AC_TYPE = "data"


def test_AC3(real_binary, fixture_env):
    """
    GIVEN: blast-radius-map with file paths + real graph.json built by a real graphify update; >=1 path resolving to a node.id
    WHEN:  graphify-enrich.py (Step 7.5) runs (gate enabled)
    THEN:  (a) resolves each modified path to bounded set of real node.id (via source_file/relative-path/label incl symbols); (b) builds focused subgraph DETERMINISTICALLY from graph.json nodes+links around those ids (primary); (c) MUST invoke real `graphify affected "<node.id>" --graph <cacheDir/graph.json> --depth N` at least once seeded with a node id that EQUALS one of the deterministic resolved_node_ids for the modified path(s) in that fixture (NOT merely any node.id in graph.json, NEVER raw paths/labels) and MUST consume its real stdout into graph_context; (d) enrichment reflects real affected output. PROOF-OF-CALL: recorded argv [graphify,affected,<resolved-node-id>] executable resolves to real…
    """
    build_cache(fixture_env, real_binary)
    write_blast_radius_map(fixture_env, ["mod_b.py"])
    ctx = fixture_env["src"] / "context.json"
    ctx.write_text('{"task_id":"t1"}', encoding="utf-8")

    r = run_script("graphify-enrich.py", ["--task-id", "t1", "--context-file", str(ctx)],
                   fixture_env["env"])
    assert r.returncode == 0, f"enrich must exit 0 (advisory): {r.stderr}"

    gc = read_json(ctx)["graph_context"]

    # (a) modified path resolved to a bounded set of real node ids.
    resolved = gc["resolved_node_ids"]
    assert resolved, "mod_b.py must resolve to >=1 real node.id"

    # (b) deterministic focused subgraph from graph.json nodes+links (>=2 nodes, >=1 edge).
    assert len(gc["nodes"]) >= 2 and len(gc["edges"]) >= 1

    # (c) real `graphify affected` invoked, seeded with a RESOLVED node id (not raw path/label).
    ar = gc["graphify_affected_results"]
    assert ar, "MUST invoke real graphify affected at least once when >=1 id resolves"
    argv = ar[0]["argv"]
    assert argv[0] == "graphify" and argv[1] == "affected"
    seed = argv[2]
    assert seed in resolved, "affected seed MUST equal one of resolved_node_ids (not any node, not a path)"
    assert seed not in ("mod_b.py",) and "/" not in seed  # not a raw path
    assert "--graph" in argv and str(fixture_env["graph_json"]) in argv and "--depth" in argv
    assert gc["affected_cli_status"] == graphify_lib.STATUS_OK
    # (d) enrichment reflects real affected output (consumed stdout present).
    assert "output" in ar[0]

    assert repo_pollution(fixture_env["src"]) == []
